class Solution:
    def maxRotateFunction(self, nums):
        n = len(nums)
        best = None
        for k in range(n):
            total = 0
            for i in range(n):
                total += i * nums[(i - k) % n]
            if best is None or total > best:
                best = total
        return best if best is not None else 0

