var maxRotateFunction = function(nums) {
    const n = nums.length;
    let total = 0, f = 0;
    for (let i = 0; i < n; i++) {
        total += nums[i];
        f += i * nums[i];
    }
    let best = f;
    for (let k = 1; k < n; k++) {
        f += total - n * nums[n - k];
        if (f > best) best = f;
    }
    return best;
};
